import React, { useEffect, useMemo, useRef, useState } from 'react';
import './ChatDemo.css';

const CHAR_CONFIG = {
  rabbit: {
    name: '하루',
    role: '차분하고 따뜻한 공감형',
    color: '#4f8cff',
    image: '/images/rabbit.png',
    welcome: '안녕하세요, 저는 하루예요. 오늘 마음은 어때요?',
    choices: ['조금 지쳤어요', '그냥 멍해요', '괜찮은 척하고 있어요'],
  },
  cat: {
    name: '루미',
    role: '밝고 다정한 에너지형',
    color: '#ff9db7',
    image: '/images/cat.png',
    welcome: '야옹, 저는 루미예요. 오늘은 어떤 하루였나요?',
    choices: ['기분이 오락가락해요', '재밌는 일도 있었어요', '조금 외로웠어요'],
  },
};

const RESPONSE_MAP = {
  '조금 지쳤어요': {
    message: '많이 애쓴 하루였겠네요. 가장 지쳤던 순간이 언제였는지 같이 떠올려볼까요?',
    choices: ['일할 때요', '사람 만날 때요', '그냥 계속 피곤해요'],
    insight: '피로 + 감정 소진 신호',
  },
  '그냥 멍해요': {
    message: '생각이 많은 날에는 마음이 멍하게 느껴질 때가 있어요. 지금은 무엇이 가장 떠오르나요?',
    choices: ['미래가 불안해요', '아무것도 하기 싫어요', '그냥 정리가 안 돼요'],
    insight: '과부하 상태 완화 필요',
  },
  '괜찮은 척하고 있어요': {
    message: '괜찮은 척하는 건 생각보다 에너지가 많이 들어요. 여기서는 솔직해도 괜찮아요.',
    choices: ['사실 많이 힘들어요', '누구한테 말 못 했어요', '조금 울고 싶어요'],
    insight: '감정 억제 패턴 감지',
  },
  '기분이 오락가락해요': {
    message: '감정이 자주 흔들릴 땐 스스로도 피곤해지죠. 오늘 특히 흔들렸던 순간이 있었나요?',
    choices: ['사람 때문이었어요', '일 때문이었어요', '이유를 모르겠어요'],
    insight: '정서 변동 폭 상승',
  },
  '재밌는 일도 있었어요': {
    message: '좋아요. 기분이 올라간 순간이 분명 있었네요. 그 순간을 조금 더 붙잡아볼까요?',
    choices: ['친구랑 웃었어요', '작은 성취가 있었어요', '오랜만에 편했어요'],
    insight: '긍정 감정 앵커 포착',
  },
  '조금 외로웠어요': {
    message: '그 외로움, 가볍게 넘기기 어려웠겠어요. 혼자라고 느낀 순간을 말해줘도 괜찮아요.',
    choices: ['퇴근 후에요', '주말에요', '사람들 사이에서도 그랬어요'],
    insight: '관계 피로 + 고립감 신호',
  },
};

const FALLBACK_RESPONSES = [
  {
    message: '지금 마음을 조금 더 말해줘도 괜찮아요. 메이티는 당신의 속도를 따라갈게요.',
    choices: ['천천히 말해볼게요', '아직 정리가 안 돼요', '들어줘서 고마워요'],
    insight: '대화 안정화 중',
  },
  {
    message: '그 감정은 그냥 지나가는 것이 아니라, 분명 의미가 있어요. 어떤 결을 가진 감정인지 같이 볼까요?',
    choices: ['불안에 가까워요', '외로움 같아요', '피곤함 같아요'],
    insight: '감정 라벨링 제안',
  },
  {
    message: '메이티는 정답을 강요하지 않아요. 지금 필요한 건 판단보다 이해일지도 몰라요.',
    choices: ['그 말이 위로돼요', '조금 더 이야기할래요', '잠깐 쉬고 싶어요'],
    insight: '안정형 공감 응답',
  },
];

function ChatDemo() {
  const [charKey, setCharKey] = useState('rabbit');
  const character = useMemo(() => CHAR_CONFIG[charKey], [charKey]);

  const [displayText, setDisplayText] = useState('');
  const [currentChoices, setCurrentChoices] = useState(character.choices);
  const [currentInsight, setCurrentInsight] = useState('초기 감정 탐색');
  const [isTyping, setIsTyping] = useState(true);
  const [isThinking, setIsThinking] = useState(false);
  const [inputText, setInputText] = useState('');
  const [messages, setMessages] = useState([
    { role: 'ai', text: character.welcome },
  ]);

  const typingRef = useRef(null);
  const demoRef = useRef(null);

  useEffect(() => {
    startTyping(character.welcome, character.choices, '초기 감정 탐색');
    setMessages([{ role: 'ai', text: character.welcome }]);
    setInputText('');
  }, [charKey]);

  useEffect(() => {
    return () => clearInterval(typingRef.current);
  }, []);

  useEffect(() => {
    const node = demoRef.current;
    if (!node) return;

    const handleMove = (e) => {
      const rect = node.getBoundingClientRect();
      const x = ((e.clientX - rect.left) / rect.width) * 100;
      const y = ((e.clientY - rect.top) / rect.height) * 100;
      node.style.setProperty('--mx', `${x}%`);
      node.style.setProperty('--my', `${y}%`);
    };

    const reset = () => {
      node.style.setProperty('--mx', '50%');
      node.style.setProperty('--my', '50%');
    };

    node.addEventListener('mousemove', handleMove);
    node.addEventListener('mouseleave', reset);

    return () => {
      node.removeEventListener('mousemove', handleMove);
      node.removeEventListener('mouseleave', reset);
    };
  }, []);

  const startTyping = (text, nextChoices, nextInsight) => {
    clearInterval(typingRef.current);
    setDisplayText('');
    setIsTyping(true);
    setCurrentChoices([]);
    setCurrentInsight(nextInsight);

    let i = 0;
    typingRef.current = setInterval(() => {
      if (i < text.length) {
        setDisplayText(text.slice(0, i + 1));
        i += 1;
      } else {
        clearInterval(typingRef.current);
        setIsTyping(false);
        setCurrentChoices(nextChoices);
      }
    }, 22);
  };

  const getReply = (text) => {
    return RESPONSE_MAP[text] || FALLBACK_RESPONSES[Math.floor(Math.random() * FALLBACK_RESPONSES.length)];
  };

  const sendMessage = (text) => {
    const trimmed = text.trim();
    if (!trimmed || isThinking || isTyping) return;

    setInputText('');
    const nextUserMessage = { role: 'user', text: trimmed };
    setMessages((prev) => [...prev, nextUserMessage]);

    setIsThinking(true);

    setTimeout(() => {
      const reply = getReply(trimmed);
      const aiMessage = { role: 'ai', text: reply.message };
      setMessages((prev) => [...prev, aiMessage]);
      startTyping(reply.message, reply.choices, reply.insight);
      setIsThinking(false);
    }, 700);
  };

  return (
    <section className="chat-demo page-section" id="chat-demo">
      <div className="container">
        <div className="section-header">
          <div className="section-badge">제품 체험</div>
          <h2 className="section-title">
            화면 속에서 바로 느껴보는
            <br />
            <span className="gradient-text">메이티의 대화 경험</span>
          </h2>
          <p className="section-subtitle">
            단순한 채팅이 아니라, 맥락을 이해하고 반응하는 AI 감정 동반자의 인터랙션을
            실제 서비스처럼 체험해보세요.
          </p>
        </div>

        <div className="chat-demo-layout">
          <aside className="chat-demo-sidebar">
            <div className="chat-side-card">
              <div className="side-card-title-row">
                <h3>AI 친구 선택</h3>
                <span className="side-card-pill">Live Demo</span>
              </div>

              <div className="character-switch-list">
                {Object.entries(CHAR_CONFIG).map(([key, item]) => (
                  <button
                    key={key}
                    className={`character-switch-btn ${charKey === key ? 'active' : ''}`}
                    onClick={() => setCharKey(key)}
                    style={{ '--char-accent': item.color }}
                  >
                    <img src={item.image} alt={item.name} />
                    <div className="character-switch-copy">
                      <strong>{item.name}</strong>
                      <span>{item.role}</span>
                    </div>
                    <div className="character-switch-dot"></div>
                  </button>
                ))}
              </div>
            </div>

            <div className="chat-side-card">
              <h3>실시간 감정 인사이트</h3>

              <div className="side-insight-panel">
                <span className="insight-mini-label">Current Analysis</span>
                <strong>{currentInsight}</strong>
                <p>대화 톤과 응답 흐름을 바탕으로 감정 상태를 부드럽게 해석합니다.</p>
              </div>

              <div className="side-mini-stats">
                <div className="mini-stat">
                  <span className="mini-stat-label">공감 톤</span>
                  <strong>높음</strong>
                </div>
                <div className="mini-stat">
                  <span className="mini-stat-label">대화 흐름</span>
                  <strong>안정적</strong>
                </div>
              </div>
            </div>
          </aside>

          <div className="chat-demo-main" ref={demoRef}>
            <div className="desktop-shell">
              <div className="desktop-shell-top">
                <div className="desktop-dots">
                  <span className="red"></span>
                  <span className="yellow"></span>
                  <span className="green"></span>
                </div>

                <div className="desktop-title">Matey Desktop Experience</div>

                <div className="desktop-status">
                  <span className="status-live-dot"></span>
                  Connected
                </div>
              </div>

              <div className="desktop-screen">
                <div className="desktop-background">
                  <div className="desktop-app-card app-code">
                    <div className="app-head">Emotion Timeline</div>
                    <div className="app-lines">
                      <span></span>
                      <span></span>
                      <span className="short"></span>
                    </div>
                  </div>

                  <div className="desktop-app-card app-memory">
                    <div className="app-head">Daily Reflection</div>
                    <div className="memory-badges">
                      <span>피로</span>
                      <span>불안</span>
                      <span>회복</span>
                    </div>
                  </div>
                </div>

                <div className="chat-widget glow-ring">
                  <div className="chat-widget-top">
                    <div className="chat-widget-avatar">
                      <img src={character.image} alt={character.name} />
                    </div>

                    <div className="chat-widget-copy">
                      <strong>{character.name}</strong>
                      <span>{character.role}</span>
                    </div>

                    <div className="chat-widget-chip">Emotion Mode</div>
                  </div>

                  <div className="chat-widget-body">
                    <div className="chat-message-list">
                      {messages.slice(-3).map((msg, index) => (
                        <div
                          key={`${msg.role}-${index}-${msg.text}`}
                          className={`chat-message-bubble ${msg.role}`}
                        >
                          {msg.role === 'ai' && index === messages.slice(-3).length - 1 ? (
                            <>
                              {displayText}
                              {(isTyping || isThinking) && (
                                <span className="chat-cursor">▌</span>
                              )}
                            </>
                          ) : (
                            msg.text
                          )}
                        </div>
                      ))}
                    </div>

                    <div className="chat-quick-actions">
                      {currentChoices.map((choice, index) => (
                        <button
                          key={`${choice}-${index}`}
                          className="chat-choice-btn"
                          onClick={() => sendMessage(choice)}
                          disabled={isTyping || isThinking}
                          style={{ animationDelay: `${index * 70}ms` }}
                        >
                          {choice}
                        </button>
                      ))}
                    </div>

                    <div className="chat-input-row">
                      <input
                        type="text"
                        value={inputText}
                        onChange={(e) => setInputText(e.target.value)}
                        onKeyDown={(e) => {
                          if (e.key === 'Enter') sendMessage(inputText);
                        }}
                        placeholder="직접 입력해서 대화를 이어보세요"
                        disabled={isTyping || isThinking}
                      />
                      <button
                        className="chat-send-btn"
                        onClick={() => sendMessage(inputText)}
                        disabled={!inputText.trim() || isTyping || isThinking}
                      >
                        →
                      </button>
                    </div>
                  </div>

                  <div className="chat-floating-badge top">대화 맥락 분석</div>
                  <div className="chat-floating-badge bottom">개인화 캐릭터 경험</div>
                </div>

                <div className="desktop-taskbar">
                  <div className="taskbar-left">🪟</div>
                  <div className="taskbar-center">
                    <span className="active">Matey</span>
                    <span>Notes</span>
                    <span>Browser</span>
                  </div>
                  <div className="taskbar-right">11:32</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default ChatDemo;
